import{_ as t,c as a,o as n,ag as r}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"The Core Functions of $DGAI: The Four-Dimensional Engine","description":"","frontmatter":{},"headers":[],"relativePath":"Core-Functions.md","filePath":"Core-Functions.md"}'),o={name:"Core-Functions.md"};function s(i,e,c,d,l,u){return n(),a("div",null,e[0]||(e[0]=[r('<h1 id="the-core-functions-of-dgai-the-four-dimensional-engine" tabindex="-1">The Core Functions of $DGAI: The Four-Dimensional Engine <a class="header-anchor" href="#the-core-functions-of-dgai-the-four-dimensional-engine" aria-label="Permalink to &quot;The Core Functions of $DGAI: The Four-Dimensional Engine&quot;">​</a></h1><p>As the native token of the network, $DGAI undertakes four core functions—staking, payment, incentives, and governance—constructing a positive ecological cycle and driving every key interaction within the DGrid AI ecosystem.</p><h2 id="staking-and-access" tabindex="-1">Staking and Access <a class="header-anchor" href="#staking-and-access" aria-label="Permalink to &quot;Staking and Access&quot;">​</a></h2><p>Nodes and AI service providers must stake $DGAI to gain network traffic, establish a reputation system, and ensure network security. Staking requirements are tiered based on node type (node performance), and staked tokens serve as collateral for violating behaviors (e.g., submitting false inference results, downtime exceeding 72 hours). Malicious nodes will face confiscation of 5–20% of staked $DGAI or temporary deactivation; these measures are automatically enforced through smart contracts.</p><h2 id="payment-for-inference-tasks" tabindex="-1">Payment for Inference Tasks <a class="header-anchor" href="#payment-for-inference-tasks" aria-label="Permalink to &quot;Payment for Inference Tasks&quot;">​</a></h2><p>Users pay with $DGAI via DGrid nodes to access Large Language Model (LLM) inference and Agent services. Fees are dynamically calculated based on the following factors:</p><ul><li><strong>Compute Unit (CU)</strong>: A standardized metric for measuring inference complexity (linked to model size, number of input tokens, and execution time).</li><li><strong>Latency</strong>: Adjusted based on task speed (faster execution earns rewards, while latency incurs minor penalties).</li></ul><p>Payments are automatically processed through the <strong>Bill Contract</strong>, a smart contract deployed on the blockchain. This contract deducts $DGAI from user accounts and distributes funds to node operators, service providers, etc., ensuring transparency and immutability of transactions.</p><h2 id="rewards-for-node-operators" tabindex="-1">Rewards for Node Operators <a class="header-anchor" href="#rewards-for-node-operators" aria-label="Permalink to &quot;Rewards for Node Operators&quot;">​</a></h2><p>The network rewards high-quality nodes and AI service providers with $DGAI based on service quality, usage volume, and user evaluations to stimulate enthusiasm for contributions. Operators earn $DGAI based on their contributions to inference tasks (e.g., number of CUs processed, low latency, and uptime). Rewards are proportional to performance—nodes hosting large models (over 13B parameters) or processing high-priority requests receive higher rewards. Rewards are distributed weekly via the Bill Contract, with detailed records archived in the AI DA Layer to ensure auditability.</p><h2 id="network-governance" tabindex="-1">Network Governance <a class="header-anchor" href="#network-governance" aria-label="Permalink to &quot;Network Governance&quot;">​</a></h2><p>$DGAI is a governance token; token holders have the right to vote on key matters related to network development, ensuring decisions align with the interests of active network participants. Proposals include:</p><ul><li>Adjusting the fee structure (e.g., base CU pricing, latency penalties).</li><li>Adding new Large Language Models (LLMs) to the whitelist for network support.</li><li>Upgrading core protocols (e.g., DGrid AI Gateway) or settlement rules.</li><li>Allocating treasury funds to promote ecosystem growth (e.g., developer grants, security audits).</li></ul><p>Voting power is proportional to staked $DGAI, ensuring decisions align with the interests of active network participants.</p>',14)]))}const g=t(o,[["render",s]]);export{p as __pageData,g as default};
